1	import { log, Node, Vec3, warn } from "cc";
2	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define from "../Game_Define";
5	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
6	import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
7	import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
8	import { Define } from "db://astarte-framework/utilis";
9	
10	export class WantedPosterState extends BaseState
11	{
12	    private m_gameView: GameView = null;
13	
14	    constructor( gameView: GameView )
15	    {
16	        super();
17	        this.m_gameView = gameView;
18	    }
19	
20	    public async OnEnter()
21	    {
22	
23	        log( "OnEnter State : WANTED_POSTER" );
24	        const plateInfo = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ]
25	            .PlateQueue[ this.m_gameView.CurPlateIndex ];
26	
27	        const awardDataVec = plateInfo.AwardDataVec ?? [];
28	        const bountyDataVec = plateInfo.BountyDataVec ?? [];
29	
30	        // BC-3：找出被消除的符號中，有哪些命中懸賞令的 BaseSymbol
31	        const triggeredBounties = this.FindTriggeredBounties( awardDataVec, bountyDataVec );
32	
33	        if ( triggeredBounties.length === 0 )
34	        {
35	
36	            stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
37	            return;
38	        }
39	
40	        // 以 BaseSymbol 分組，同組合併成一隻 spine（連乘）
41	        const basePlateIndexes = plateInfo.BasePlateIndex ?? [];
42	        const groups = this.GroupBountiesByBaseSymbol( triggeredBounties );
43	
44	        // 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本狀態只播懸賞令 spine 演出；
45	        // 多個不同 BaseSymbol 群組改為「並行」一起演出（不再逐組序列）。
46	        await Promise.all( groups.map( group => this.PlayBountyGroupPerform(
47	            group, awardDataVec, plateInfo.PlateSymbol, basePlateIndexes
48	        ) ) );
49	
50	        stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
51	    }
52	
53	    public OnProcess() { }
54	
55	    public OnLeave() { }
56	
57	    /**
58	     * @ch 對「一組同 BaseSymbol 的懸賞」執行 ①Mark → ②Symbol_In → ③(Mark_Active ∥ Symbol_Active) → ④底板SET
59	     *
60	     * 透過 WANTED_POSTER_MANAGER_EVENT 與常駐 WantedPosterManager 溝通；
61	     * 場上 Wanted Spine 由 EffectPlate.SpawnAndPlayWantedSymbolIn / PlayWantedSymbolActiveAndRecycle 直接呼叫
62	     *
63	     * 合併語意：同組所有 bounty 共用同一 BaseSymbol（前提②）與同一組位置
64	     * （同 BaseSymbol → awardDataVec 對應唯一一筆 award），故 spawn 只跑一次。
65	     *
66	     * BC-4：對該 BaseSymbol 的所有常駐 item 同時播 Mark → Mark_Active，最後各自 active=false（Manager.OnEvent 內處理）
67	     * BC-6：階段 ③ Mark_Active 與 Symbol_Active 同 Promise.all 起播
68	     * BC-7：場上 spine 顯示組內 Multiple 連乘（純表演）
69	     * 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本方法不再消除，只播 spine 演出。
70	     * EH-1：找不到對應 item 由 Manager 內部 warn + 立刻 resolve，不阻斷流程
71	     */
72	    private async PlayBountyGroupPerform(
73	        group: protocol.ar2pq9Proto.IBountyData[],
74	        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
75	        curPlateSymbol: protocol.ar2pq9Proto.IColumn[],
76	        basePlateIndexes: protocol.ar2pq9Proto.IIntAry[]
77	    ): Promise<void>
78	    {
79	        if ( group.length === 0 ) return;
80	
81	        // 組內共同 BaseSymbol（前提②：同 BaseSymbol 的 BountySymbol 一定相同）
82	        const baseSymbol = group[ 0 ].BaseSymbol;
83	        if ( baseSymbol === null || baseSymbol === undefined )
84	        {
85	            warn( '[WantedPosterState] PlayBountyGroupPerform: BaseSymbol 為空，跳過' );
86	            return;
87	        }
88	
89	        // 位置由組內共同 BaseSymbol 單次取得（與組內筆數無關）
90	        const matchedAward = awardDataVec.find(
91	            award => award.Symbol === baseSymbol
92	                && award.EliminatePos
93	                && award.EliminatePos.length > 0
94	        );
95	        if ( !matchedAward ) return;
96	
97	        // 過濾掉 Wild 位置（spine 與 ④底板只跑非 wild；wild 的消除/底板已在 ExplodeState 處理）
98	        const filteredPositions = this.FilterNonWildPositions(
99	            matchedAward.EliminatePos!, curPlateSymbol
100	        );
101	        // 無非 wild 位置 → 無 spine 可演（wild 消除已在 ExplodeState 完成）
102	        if ( filteredPositions.length === 0 ) return;
103	
104	        // 場上 spine 顯示倍率 = 組內 Multiple 連乘（純表演）
105	        const multiplier = this.ComputeGroupMultiplier( group );
106	
107	        // 把 positions(一維索引) 轉為世界座標（事件 payload 用世界座標，避免在 manager 跨越 SlotReels 依賴）
108	        const worldPositions = filteredPositions.map( pos => {
109	            const col = Math.floor( pos / Game_Define.ROW );
110	            const row = pos % Game_Define.ROW;
111	            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( col, row );
112	        } );
113	
114	        // ① Mark — 事件 + Promise wrapper（同 EffectPlate 對 MULTIPLIER_BASE_MANAGER 的風格）
115	        await new Promise<void>( resolve => {
116	            eventManager.Dispatch(
117	                WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
118	                baseSymbol,
119	                resolve
120	            );
121	        } );
122	
123	        // ② 懸賞令 spine 進場（Symbol_In）。symbol/wild 消除已在 ExplodeState 步驟①完成，此處不再消除
124	        const spawnedNodes: Node[] = await this.m_gameView.EffectPlate.SpawnAndPlayWantedSymbolIn(
125	            worldPositions, baseSymbol, multiplier
126	        );
127	
128	        // ③ Mark_Active ∥ Symbol_Active 同時起播
129	        await Promise.all( [
130	            new Promise<void>( resolve => {
131	                eventManager.Dispatch(
132	                    WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
133	                    baseSymbol,
134	                    resolve
135	                );
136	            } ),
137	            this.m_gameView.EffectPlate.PlayWantedSymbolActiveAndRecycle( spawnedNodes ),
138	        ] );
139	
140	        // ④ 場上 Wanted 表演完成後，更新懸賞令位置的乘倍底板（帶 Spine 動畫）
141	        // 移到組末才升底板，避免被階段②/③的 Spine 動畫分散視覺焦點
142	        await Define.Wait( this.m_gameView, 0.5 );
143	        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true );
144	        const upgradePromises: Promise<void>[] = [];
145	        for ( const pos of filteredPositions )
146	        {
147	            const col = Math.floor( pos / Game_Define.ROW );
148	            const row = pos % Game_Define.ROW;
149	            upgradePromises.push( new Promise<void>( resolve =>
150	            {
151	                eventManager.Dispatch(
152	                    MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM,
153	                    pos,
154	                    basePlateIndexes[ col ].Data[ row ],
155	                    resolve
156	                );
157	            } ) );
158	        }
159	        await Promise.all( upgradePromises );
160	    }
161	
162	    /**
163	     * @ch BC-1：將已觸發的 bounty 以 BaseSymbol 分組
164	     * 同 BaseSymbol 歸同組；組順序依各 BaseSymbol 首次出現順序，組內保留原順序。
165	     * 輸入契約：吃 FindTriggeredBounties 的輸出（已觸發子集），非原始 bountyDataVec。
166	     */
167	    private GroupBountiesByBaseSymbol(
168	        bounties: protocol.ar2pq9Proto.IBountyData[]
169	    ): protocol.ar2pq9Proto.IBountyData[][]
170	    {
171	        const groups: protocol.ar2pq9Proto.IBountyData[][] = [];
172	        const groupIndexByBaseSymbol = new Map<number, number>();
173	        for ( const bounty of bounties )
174	        {
175	            const key = bounty.BaseSymbol;
176	            if ( key === null || key === undefined ) continue;
177	            const existing = groupIndexByBaseSymbol.get( key );
178	            if ( existing !== undefined )
179	            {
180	                groups[ existing ].push( bounty );
181	            }
182	            else
183	            {
184	                groupIndexByBaseSymbol.set( key, groups.length );
185	                groups.push( [ bounty ] );
186	            }
187	        }
188	        return groups;
189	    }
190	
191	    /**
192	     * @ch BC-2：組內 Multiple 連乘（純函式）
193	     * DR-9：Multiple 為 null/undefined/非有限數 → 視為中性值 1（跳過不計），避免連乘塌成 0。
194	     * 空組回 1。
195	     */
196	    private ComputeGroupMultiplier(
197	        group: protocol.ar2pq9Proto.IBountyData[]
198	    ): number
199	    {
200	        let product = 1;
201	        for ( const bounty of group )
202	        {
203	            const m = bounty.Multiple;
204	            if ( m !== null && m !== undefined && Number.isFinite( m ) )
205	            {
206	                product *= m;
207	            }
208	        }
209	        return product;
210	    }
211	
212	    /**
213	     * @ch 找出被消除的符號中命中懸賞令的資料
214	     * BC-3：EliminatePos.length > 0 代表該符號有被消除；
215	     *       若其 Symbol 值等於某懸賞令的 BaseSymbol，則該懸賞令被觸發。
216	     * R-4：award.Symbol / bounty.BaseSymbol 在 proto 是 number|null，過濾掉 null/undefined 避免污染 Set
217	     */
218	    private FindTriggeredBounties(
219	        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
220	        bountyDataVec: protocol.ar2pq9Proto.IBountyData[]
221	    ): protocol.ar2pq9Proto.IBountyData[]
222	    {
223	        if ( awardDataVec.length === 0 || bountyDataVec.length === 0 )
224	        {
225	            return [];
226	        }
227	
228	        // 收集本次被消除的符號 ID
229	        const eliminatedSymbols = new Set<number>();
230	        for ( const award of awardDataVec )
231	        {
232	            if ( award.EliminatePos && award.EliminatePos.length > 0
233	                && award.Symbol !== null && award.Symbol !== undefined )
234	            {
235	                eliminatedSymbols.add( award.Symbol );
236	            }
237	        }
238	
239	        // 比對懸賞令的 BaseSymbol
240	        return bountyDataVec.filter( bounty =>
241	            bounty.BaseSymbol !== null && bounty.BaseSymbol !== undefined
242	            && eliminatedSymbols.has( bounty.BaseSymbol )
243	        );
244	    }
245	
246	    /**
247	     * @ch 過濾掉 Wild 位置，只保留實際為 BaseSymbol 的位置
248	     */
249	    private FilterNonWildPositions(
250	        positions: number[],
251	        curPlateSymbol: protocol.ar2pq9Proto.IColumn[]
252	    ): number[]
253	    {
254	        return positions.filter( pos =>
255	        {
256	            const col = Math.floor( pos / Game_Define.ROW );
257	            const row = pos % Game_Define.ROW;
258	            const sym = curPlateSymbol?.[ col ]?.Col?.[ row ] ?? -1;
259	            return sym !== Game_Define.Symbol.Wild;
260	        } );
261	    }
262	
263	}
