/**@ch AwardState結束後，看要往哪裡去=>只去ROUND SHOW END */
async AfterShowWin()
{
    if ( !this.IsFreeGame && !this.IsGoingToFree ) this.SetManualVisible( true );
    stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
}
//#endregion 狀態機
//=============================================================

//=============================================================
//#region ConnectionManager
// ConnectionManager需實作 OnCommand、GetSpinInfo、CancelSpin
OnCommand( type: number, data: Uint8Array )
{

    switch ( type )
    {
        case Define.AckType.info:
            {

                eventManager.Dispatch(GAME_INTRO_MANAGER_EVENT.INIT, this);

                eventManager.Dispatch(REEL_UI_MANAGER_EVENT.INIT, this);

                // 連線初始 → 清空懸賞令（isNewRound=true 整批重建為空）
                eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, [], true);

                let info: protocol.ar2pq9Proto.IGameInfoData = protocol.ar2pq9Proto.GameInfoData.decode( data );
                error( "GameInfo is", info );

                // 本次連線 server 是否提供 ExtraBet（gate 集中於 GameView 各入口方法）
                this.m_showExtra = info.ShowExtra ?? false;

                this.SetTxt();
                this.SettingBottomBar();

                 // 發送更新Logo圖片事件
                 eventManager.Dispatch(REEL_UI_MANAGER_EVENT.UPDATE_LOGO);

                newBottombarManager.AutoPlayPanelInit();
                newExtraManager.FeaturesInit(
                    [ "features/left/spriteFrame", "features/right/spriteFrame" ],
                    [ Game_Define.StringKey.MC_FEATURES_LEFT, Game_Define.StringKey.MC_FEATURES_RIGHT ],
                    Game_Define.SPICY_LEVEL,
