import { _decorator, log } from "cc";
import { stateManager, BaseState, newBottombarManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import { REEL_UI_MANAGER_EVENT, UIType } from "../Reel/ReelManager";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { FREE_GAME_EXIT_MANAGER_EVENT } from "../FreeGame/FreeGameExitManager";
import { BACKGROUND_MANAGER_EVENT, BackgroundType } from "../BackgroundManager";
import { Common } from "../Common/Common";
import { AudioManager } from "../Audio/AudioManager";
import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";

const { ccclass } = _decorator;
@ccclass( "LeaveFreeState" )
export class LeaveFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : LeaveFreeState" );
        this.LeaveFreeSetting();
    }

    async LeaveFreeSetting()
    {


        Common.SetLockOrientation(true);

        newBottombarManager.SetBarNodeVisiable( false );

        newBottombarManager.SetLeaveFree();
        newBottombarManager.LockBetEnable( true );
        this.StopEffect(); // 請要停止的效果都放在這裡

        // ==================== 離開時的處理 ====================

        // 設置免費遊戲狀態為false
        this.m_gameView.IsFreeGame = false;
        this.m_gameView.FreePickItems = [];

        // 清除 active feature icon
        eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.CLEAR_ACTIVE_FEATURES);

        // 切換到主遊戲UI
        await this.SetMainGameUI();


        // 設置主遊戲下注介面可見
        newBottombarManager.SetBarNodeVisiable( true );
        this.m_gameView.BuyBonus?.SetBuyBtnVisible( true );
        this.m_gameView.SetExtraBetVisible( true );
        this.m_gameView.SetManualVisible( true );

        // 停止免費遊戲BGM
        this.m_gameView.StopFreeGameBgm();

        // 設置是否回到主遊戲並消除Scatter為true
        // 如果CurRoundIndex是最後一局，則不設置


        // 播放MainGame BGM
        this.m_gameView.ResumeMainGameBgm();

        Common.SetLockOrientation(false);

        // NextState
        stateManager.NextState( Game_Define.GameState.ROUND_END );
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }

    /**
     * @ch 停止效果
     * @returns {void}
     */
    private StopEffect(): void
    {
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        this.m_gameView.ClearAll();
    }

    /**
     * @ch 播放離場Spine動畫
     */
    private async PlayOutSpineAnim() : Promise<void>
    {
        return new Promise<void>((resolve) => {
            const index = this.m_gameView.IsLandscape ? 0 : 1;
            eventManager.Dispatch(FREE_GAME_EXIT_MANAGER_EVENT.PLAY_OUT_SPINE_ANIM, index, 
                this.m_gameView.RoundInfo.FeverTotalRound, 
                this.m_gameView.SpinAck.TotalWin, 
                () => {
                    resolve();
            });
        });
    }

    /**
     * @ch 設定主遊戲UI
     */
    private async SetMainGameUI()
    {
        // FG 結束後等 1 秒再跳出結算面板
        await Define.Wait( this.m_gameView, 2.0 );

        // 切換到主遊戲UI
        eventManager.Dispatch( REEL_UI_MANAGER_EVENT.CHANGE_UI, UIType.MainGame );

        // 切換到主遊戲背景
        eventManager.Dispatch( BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, BackgroundType.MainGame );



        // 播放離場Spine動畫
        await this.PlayOutSpineAnim();
    }

    /**
     * @ch 播放總贏分報獎動畫
     */
    private async PlayTotalWinAward() {
        const SpinAck = this.m_gameView.SpinAck;
        const totalWin: number = SpinAck.TotalWin;
        const bet: number = Game_Define.GetNowBetValue();
        const rate = totalWin / bet;

        if ( totalWin <= 0 || rate < Game_Define.BigWinWinRule.BIG_WIN_MIN ) return;

        let lvl = 1;
        if ( rate >= Game_Define.BigWinWinRule.SUPER_WIN_MIN ) lvl = 3;
        else if ( rate >= Game_Define.BigWinWinRule.MEGA_WIN_MIN ) lvl = 2;

        this.m_gameView.ShowBigWin( totalWin, lvl );
        this.m_gameView.FadeBgmOut();

        // 等待 BigWin 結束
        while ( !this.m_gameView.BigWin.IsEnd ) {
            await Define.Wait( this.m_gameView, 0.1 );
        }
        this.m_gameView.BigWin.node.active = false;
        this.m_gameView.FadeBgmIn();
    }
}

